arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    //---------- Movement ----------
    if yVel=0 and bJumpReady=1
    {
      image_speed=0.25
      sprite_index=sGreenOrcWalk
      if x<oPlayer1.x
      {
        image_xscale=1
        xVel=runAcc
      }
      else
      {
        image_xscale=-1
        xVel=-runAcc
      }
    }
    else
    {
      image_speed=0
      sprite_index=sGreenOrcJump
      if yVel<0
        image_index=0
      else
        image_index=1
    }
    
    //Check if cliff edge and jump
    if yVel=0 and bJumpReady=1
    {
      var tDrop;
      tDrop=0
      if aiCheckHoriz(1,1,0,16,4)
      {
        if aiCheckVert(0,3,24,16,4)=1
        {
          tDrop=1
        }
      }
      
      if tDrop=0
      {
        xVel=(runAcc*1.25)*image_xscale
        y-=4
        yVel=-6
        bJumpReady=0
      }
    }
    
    /*if !collision_point(x+(16*image_xscale),y+4,oSolid,0,1) and yVel=0 and bJumpReady=1
    {
      var tDrop;
      tDrop=0
      for(i=0;i<3;i+=1)
      {
        if collision_point(x+(16*image_xscale),y+4+(i*24),oSolid,0,1)
        {
          tDrop=1
          break;
        }
      }
      
      if tDrop=0
      {
        xVel=(runAcc*1.25)*image_xscale
        y-=4
        yVel=-6
        bJumpReady=0
      }
    }*/
    
    yVel+=0.25
    if isCollisionBottom(1)
    {
      yVel=0
      bJumpReady=1
    }
    if isCollisionLeft(1)
      xVel=runAcc
    if isCollisionRight(1)
      xVel=-runAcc
    if isCollisionSolid()
      y-=2
    
    moveTo(xVel,yVel)
    if y>room_height+24
      instance_destroy()
  }
  enemyStepEvent()
}
